    def validate_token(self, access_token: str) -> Optional[Dict[str, str]]:
        if access_token not in self.access_tokens:
            return None
        
        token_obj = self.access_tokens[access_token]
        
        if datetime.now() > token_obj.expires_at:
            return None
        
        return {
            'client_id': token_obj.client_id,
            'scope': token_obj.scope,
            'user_id': token_obj.user_id
        }

    def add_user(self, username: str, password: str) -> str:
        user_id = secrets.token_urlsafe(16)
        password_hash = hashlib.sha256(password.encode()).hexdigest()
        self.users[username] = password_hash
        return user_id

    def authenticate_user(self, username: str, password: str) -> Optional[str]:
        if username not in self.users:
            return None
        
        password_hash = hashlib.sha256(password.encode()).hexdigest()
        if self.users[username] == password_hash:
            return username
        
        return None


